template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the actual number of bytes available to peek
    size_t available = buffer.size();
    size_t to_peek = std::min(bytes_to_peek, available);

    // Create vector to hold the peeked data
    std::vector<uint8_t> result(to_peek);

    // Peek the data without advancing read pointer
    if (to_peek > 0) {
        buffer.peek(result.data(), to_peek);
    }

    return result;
}

