template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block allocator for int types with element_count blocks
    // The allocator internally maintains a free list of available blocks
    hexi::block_allocator<int> allocator(element_count);

    std::cout << "=== Demonstrating Block Allocator Free List Management ===" << std::endl;
    std::cout << "Block allocator created with " << element_count << " blocks\n" << std::endl;

    // Phase 1: Allocate blocks (demonstrates internal pop() from free list)
    std::cout << "Phase 1: Allocating blocks (internally calls pop())" << std::endl;
    std::cout << "  pop() removes blocks from the HEAD of the free list\n" << std::endl;

    std::vector<int*> allocated_blocks;

    for (size_t i = 0; i < 5; ++i) {
        int* block = allocator.allocate();
        if (block) {
            *block = static_cast<int>(i * 100); // Mark the block with a value
            allocated_blocks.push_back(block);
            std::cout << "  Allocated block " << i << " at address: " << block 
                      << ", marked with value: " << *block << std::endl;
        }
    }

    std::cout << "\nCurrent state: 5 blocks allocated, " 
              << (element_count - 5) << " blocks remain in free list\n" << std::endl;

    // Phase 2: Deallocate some blocks (demonstrates internal push() to free list)
    std::cout << "Phase 2: Deallocating blocks (internally calls push())" << std::endl;
    std::cout << "  push() adds blocks to the HEAD of the free list (LIFO behavior)\n" << std::endl;

    // Store addresses and values before deallocating
    std::vector<std::pair<int*, int>> deallocated_info;
    for (int idx : {1, 2, 3}) {
        int* addr = allocated_blocks[idx];
        int val = *addr;
        deallocated_info.push_back({addr, val});

        std::cout << "  Deallocating block at address: " << addr
                  << " (value: " << val << ")" << std::endl;

        allocator.deallocate(addr);
        allocated_blocks[idx] = nullptr;
    }

    std::cout << "\nCurrent state: 2 blocks still allocated, " 
              << (element_count - 2) << " blocks in free list" << std::endl;
    std::cout << "  Free list order (HEAD to tail): " 
              << "block[3] -> block[2] -> block[1] -> (original free blocks)...\n" << std::endl;

    // Phase 3: Allocate again to demonstrate LIFO behavior
    std::cout << "Phase 3: Re-allocating blocks (demonstrates LIFO - Last In First Out)" << std::endl;
    std::cout << "  Since push() adds to HEAD and pop() removes from HEAD," << std::endl;
    std::cout << "  we expect to get blocks in reverse order of deallocation\n" << std::endl;

    for (size_t i = 0; i < 3; ++i) {
        int* block = allocator.allocate();
        if (block) {
            std::cout << "  Re-allocated block at address: " << block;

            // Verify LIFO behavior: should get blocks in reverse deallocation order
            // deallocated: block[1], block[2], block[3]
            // expected re-allocation: block[3], block[2], block[1]
            size_t expected_idx = deallocated_info.size() - 1 - i;
            if (block == deallocated_info[expected_idx].first) {
                std::cout << " ✓ LIFO confirmed! (was deallocated " 
                          << (expected_idx == 2 ? "last" : expected_idx == 1 ? "2nd" : "3rd")
                          << ", value was: " << deallocated_info[expected_idx].second << ")";
