        unsigned_value >>= 7; // Shift right by 7 bits

        // Set continuation bit if more bytes remain
        if (unsigned_value != 0) {
            byte |= 0x80;
        }

        writer.write(byte);
        bytes_written++;
    } while (unsigned_value != 0);

    return bytes_written;
}
