    uintptr_t src_start = reinterpret_cast<uintptr_t>(src);
    uintptr_t src_end = src_start + src_len;
    uintptr_t dst_start = reinterpret_cast<uintptr_t>(dst);
    uintptr_t dst_end = dst_start + dst_len;

