    d >> hexi::varint(packet.packet_id);

    // Deserialize tags vector with varint length prefix
    // prefixed_varint reads the size as varint, then reads that many elements
    d >> hexi::prefixed_varint(packet.tags);

    // Deserialize data string with varint length prefix
    d >> hexi::prefixed_varint(packet.data);

    return packet;
}
